import{_ as e,c as o,o as l,ag as a}from"./chunks/framework.DD2hp6gW.js";const u=JSON.parse('{"title":"Color Swatch Field","description":"","frontmatter":{},"headers":[],"relativePath":"fields/color-swatch.md","filePath":"fields/color-swatch.md","lastUpdated":null}'),i={name:"fields/color-swatch.md"};function n(s,t,r,d,c,h){return l(),o("div",null,t[0]||(t[0]=[a('<h1 id="color-swatch-field" tabindex="-1">Color Swatch Field <a class="header-anchor" href="#color-swatch-field" aria-label="Permalink to &quot;Color Swatch Field&quot;">​</a></h1><p>The <strong>Color Swatch</strong> field displays options as solid colored blocks that customers can click to select. This provides a visually intuitive way to choose colors without relying on text labels.</p><h2 id="common-use-cases" tabindex="-1">Common Use Cases <a class="header-anchor" href="#common-use-cases" aria-label="Permalink to &quot;Common Use Cases&quot;">​</a></h2><ul><li>Selecting the primary color of a garment (Red, Blue, Green)</li><li>Choosing a paint color for a custom product</li><li>Picking a hardware finish (Gold, Silver, Matte Black, Rose Gold)</li><li>Selecting a thread or ink color for embroidery or printing</li></ul><h2 id="field-settings" tabindex="-1">Field Settings <a class="header-anchor" href="#field-settings" aria-label="Permalink to &quot;Field Settings&quot;">​</a></h2><p>When you add a Color Swatch field and expand it in the builder, the following settings are available:</p><h3 id="general" tabindex="-1">General <a class="header-anchor" href="#general" aria-label="Permalink to &quot;General&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Setting</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Label</strong></td><td style="text-align:left;">The title displayed above the swatch grid (e.g., &quot;Select Your Color&quot;).</td></tr><tr><td style="text-align:left;"><strong>Description</strong></td><td style="text-align:left;">Optional help text shown below the swatches.</td></tr><tr><td style="text-align:left;"><strong>Required</strong></td><td style="text-align:left;">When checked, the customer must select a color before adding the product to the cart.</td></tr></tbody></table><h3 id="display-style" tabindex="-1">Display Style <a class="header-anchor" href="#display-style" aria-label="Permalink to &quot;Display Style&quot;">​</a></h3><p>You can choose how the swatch options are rendered on the frontend:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Style</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Swatch Only</strong></td><td style="text-align:left;">Shows just the colored block. Clean and minimal.</td></tr><tr><td style="text-align:left;"><strong>Swatch + Label</strong></td><td style="text-align:left;">Shows the colored block with the choice label text below it (e.g., &quot;Ocean Blue&quot;). Useful when exact color names matter.</td></tr></tbody></table><h3 id="choices-options" tabindex="-1">Choices (Options) <a class="header-anchor" href="#choices-options" aria-label="Permalink to &quot;Choices (Options)&quot;">​</a></h3><p>You must define at least one choice. Each choice has the following columns:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Column</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Color</strong></td><td style="text-align:left;">Click the color preview block to open a native color picker. Select the exact hex color (e.g., <code>#FF5733</code> for a warm red-orange).</td></tr><tr><td style="text-align:left;"><strong>Label</strong></td><td style="text-align:left;">The text identifying this choice (e.g., &quot;Midnight Blue&quot;). The <strong>Value</strong> is automatically generated from the label.</td></tr><tr><td style="text-align:left;"><strong>Price</strong></td><td style="text-align:left;">The numeric amount to add to the product price when this color is selected. Only visible when Price Type is not &quot;No Price&quot;.</td></tr><tr><td style="text-align:left;"><strong>Price Type</strong></td><td style="text-align:left;">How this choice affects pricing. Options: <strong>No Price</strong>, <strong>Flat Fee</strong>, <strong>Percentage of Base</strong>, or <strong>Formula</strong>. Each choice can have its own independent price type.</td></tr><tr><td style="text-align:left;"><strong>Weight</strong></td><td style="text-align:left;">Additional shipping weight to add when this choice is selected.</td></tr></tbody></table><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>The <strong>size and shape</strong> of color swatches are configured globally in <strong>WooCommerce &gt; Settings &gt; OptionBay</strong>. Use the &quot;Swatch Size&quot; setting to control dimensions and &quot;Swatch Radius&quot; to switch between square (<code>4px</code>) and circular (<code>50%</code>) shapes.</p></div><p>You can add new choices using the <strong>+ Add Choice</strong> button and remove them using the trash icon.</p><h2 id="conditional-logic" tabindex="-1">Conditional Logic <a class="header-anchor" href="#conditional-logic" aria-label="Permalink to &quot;Conditional Logic&quot;">​</a></h2><p>You can show or hide this field based on the value of another field in the same group. For example, show a &quot;Thread Color&quot; swatch only when the customer checks an &quot;Add Custom Embroidery?&quot; checkbox.</p><p>For full details on setting up rules, see the <a href="./../conditional-logic.html">Conditional Logic</a> page.</p>',19)]))}const p=e(i,[["render",n]]);export{u as __pageData,p as default};
